function parseTimes(timeString) {
    const timeRegex = /(\d{2}:\d{2})\s*-\s*(\d{2}:\d{2})/;
    const match = timeString.match(timeRegex);
    if (!match) return { startTime: 0, endTime: 0 };

    function toMinutes(t) {
      const [hours, minutes] = t.split(':').map(Number);
      return hours * 60 + minutes;
    }

    const timeParts = [toMinutes(match[1]), toMinutes(match[2])].sort((a, b) => a - b);

    return {
      startTime: timeParts[0],
      endTime: timeParts[1]
    };
  }

  function getDayNumber(text) {
    if (text.includes("السبت")) return [0];
    if (text.includes("الأحد") || text.includes("الاحد")) return [1];
    if (text.includes("الاثنين") || text.includes("الإثنين")) return [2];
    if (text.includes("الثلاثاء")) return [3];
    if (text.includes("الأربعاء") || text.includes("الاربعاء")) return [4];
    if (text.includes("الخميس")) return [5];
    if (text.includes("الجمعة")) return [6];
    return [];
  }

  function getPlace(text) {
    const placeRegex = /(قاعات\s+[^\(]+)\s*\d{2}:\d{2}\s*-\s*\d{2}:\d{2}\s*\(([^)]+)\)/;
    const match = text.match(placeRegex);

    if (match) {
      return `${match[1].trim()} - ${match[2].trim()}`;
    }

    if (text.includes("قاعات النوفليين")) {
      const hallMatch = text.match(/(قاعة\s*\d+)/);
      const hall = hallMatch ? hallMatch[1].trim() : "";
      return hall ? `قاعات النوفليين - ${hall}` : "قاعات النوفليين";
    }

    return "غير محدد";
  }

  const schedule = {};
  const table = document.getElementById("new_style");

  if (!table) return JSON.stringify({});

  const rows = table.querySelectorAll("tbody tr");

  rows.forEach(row => {
    if (row.id === "head_td" || row.querySelector("th")) return;

    const cells = row.querySelectorAll("td");
    if (cells.length < 6) return;

    const groupDetails = cells[0].innerText.trim();
    const courseName = cells[1].innerText.trim();

    const times = parseTimes(groupDetails);
    const days = getDayNumber(groupDetails);
    const place = getPlace(groupDetails);

    const timingEntry = {
      doctor: "",
      place: place,
      startTime: times.startTime,
      endTime: times.endTime,
      days: days
    };

    if (!schedule[courseName]) {
      schedule[courseName] = {
        courseCode: "",
        timings: [timingEntry]
      };
    } else {
      schedule[courseName].timings.push(timingEntry);
    }
  });

  return JSON.stringify(schedule);
